import { ComponentContext } from "@teambit/generator";

export function specFile(context: ComponentContext) {
  return {
    relativePath: `${context.name}.spec.tsx`,
    content: `import { render } from '@testing-library/react';
import { ${context.namePascalCase} } from './${context.name}.js';

it('should render without errors', () => {
  const { container } = render(<${context.namePascalCase} />);
  expect(container).toBeTruthy();
});
`
  }
}
